static void weights_bind_layer(ds4_layer_weights *l, const ds4_model *m, uint32_t il) {
    const uint32_t compress_ratio = ds4_layer_compress_ratio(il);

    l->hc_attn_fn      = required_tensorf(m, "blk.%u.hc_attn_fn.weight", il);
